export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰離開了高科技園區，搭地鐵回市區。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "地鐵車廂裡擠滿了人。上班族、學生、帶著大包小包的遊客。李杰站在角落，看著窗外飛逝的風景。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "地鐵廣播用中文和英文報著站名。李杰閉上眼睛，聽著那熟悉的聲音。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）已經...兩年沒回來了..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）這個聲音...這個擁擠的感覺...都沒變..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "地鐵到了人民廣場站。李杰下車，走上地面。傍晚的上海，天色漸暗，街道上的霓虹燈開始亮起。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰走進一家小餐館。餐館不大，只有十幾張桌子。牆上貼著手寫的菜單，空氣中飄著油煙和食物的香味。" },
    { characterId: CharacterId.InnKeeper, character: "老闆", dialogue: "（上海話）小夥子，吃點啥？" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（用標準中文）一籠小籠包...還有一碗餛飩..." },
    { characterId: CharacterId.InnKeeper, character: "老闆", dialogue: "（點頭）好咧！" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰找了個靠窗的位子坐下。窗外是繁忙的街道。電動車、計程車、行人，川流不息。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不一會兒，老闆端來了小籠包。熱騰騰的蒸籠，白色的薄皮裡透著湯汁。李杰夾起一個，小心地咬開一個小口，吸著湯汁。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）這個味道..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "熟悉的味道。鮮美的肉餡，燙口的湯汁。李杰閉上眼睛，慢慢品嚐。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "餛飩也來了。清湯裡飄著蔥花和紫菜。李杰喝了一口湯，溫暖的感覺從胃裡散開。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）兩年了...終於又吃到了..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但這次不一樣。李杰看著窗外的街景。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）這次...我是以斎藤的身分回來的..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）不能去見朋友...不能回家..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）明明是自己的城市...卻像個遊客..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰慢慢地吃完了飯。他付錢離開，走在熟悉又陌生的街道上。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "接下來的幾天，李杰繼續在上海調查。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他試著在網路上搜尋，在社群網站上找線索。但依然一無所獲。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "調查之餘，李杰也在上海到處走走。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他去了外灘。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "傍晚的外灘，人潮湧動。遊客們舉著手機，對著對岸的高樓大廈拍照。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "黃浦江對岸，東方明珠塔的燈光閃爍。環球金融中心、上海中心大廈，一棟棟摩天大樓點亮了天際線。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰站在欄杆邊，看著江面上的遊船緩緩駛過。江風吹來，帶著水氣。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）兩年前...我也站在這裡..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）那時候...我還是李杰..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "現在，他是斎藤蓮。一個日本遊客。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰看著對岸的燈光。那些高樓裡，有多少人正在加班。有多少人正在回家。有多少人正在做著自己的夢。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）我的夢...是什麼..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）找到大輔...找到爸媽...然後呢..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰沒有答案。他只是靜靜地站著，看著江水流淌。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他去了城隍廟。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "古色古香的建築，彎曲的屋簷，紅色的燈籠。遊客們在小吃攤前排隊。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰買了一串糖葫蘆，又買了一份生煎包。熱騰騰的生煎包，底部焦脆，咬下去滿口湯汁。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他坐在廟前的廣場上，看著來來往往的遊客。有人在拍照，有人在買紀念品，有人在許願。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰看著那些遊客。他們臉上都帶著笑容。旅行的快樂，探索的興奮。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心，苦笑）作為日本遊客在上海玩...還挺有趣的..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）如果不是為了找大輔...這趟旅行應該會很愉快..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰吃完生煎包，起身離開。他走在城隍廟的街道上，看著兩旁的商店。賣絲綢的、賣茶葉的、賣紀念品的。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一切都那麼熟悉，又那麼遙遠。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "有一次，李杰在一家本幫菜餐廳吃飯。他點了紅燒肉、糖醋小排、還有一碗白米飯。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "餐廳裡坐滿了人。大多是本地人，也有一些遊客。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰坐在角落，低頭吃飯。隔壁桌坐著兩個中年男子，正在聊天。" },
    { characterId: CharacterId.Passerby, character: "路人甲", dialogue: "（用上海話）儂看，個個日本人..." },
    { characterId: CharacterId.Passerby, character: "路人乙", dialogue: "（也用上海話）對啊...儂看伊個樣子...應該是遊客吧..." },
    { characterId: CharacterId.Passerby, character: "路人甲", dialogue: "（繼續說）現在日本人蠻多額...儂看伊點額菜，紅燒肉、糖醋小排...都是本幫菜..." },
    { characterId: CharacterId.Passerby, character: "路人乙", dialogue: "（笑著）伊曉得吃額嘛...日本人來上海，就歡喜吃中國菜..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰聽懂了他們的話。但他沒有表現出來，繼續低頭吃飯。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）如果他們知道我其實是上海人...不知道會是什麼表情..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）如果我用上海話跟他們說話...他們一定會嚇一跳..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但李杰不能這麼做。他現在是斎藤蓮，一個日本人。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這種感覺很奇妙。明明是自己的城市，卻要假裝是外國人。明明聽得懂上海話，卻要裝作聽不懂。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）也算是...特別的體驗吧..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）只是...這種體驗...不太好受..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰吃完飯，付了錢，默默離開。走在街上，他聽著周圍的上海話，心裡五味雜陳。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "兩週很快過去了。李杰在上海的調查沒有任何進展。大輔的住址找不到，也沒有其他線索。第十三天晚上，李杰坐在酒店房間裡，看著窗外的夜景。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（嘆氣）該回去了..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）繼續待在這裡...也沒有意義..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）而且...盒子的事...我一個人也想不出來..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）回去...跟颯真他們商量..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）也許...他們能想到什麼辦法..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第十四天，李杰去了幾個以前常去的地方。這是在上海的最後一天。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他去了母校。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "大學的校門。李杰站在對面的街道，遠遠地看著。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "下午三點多，陽光灑在校園裡。有學生走出校門，有學生走進去。他們背著書包，拿著筆記本，有說有笑。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）以前...我也是這裡的學生..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）每天上課...和同學一起討論作業...在圖書館待到很晚..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰看著那些學生。他們的臉上寫滿了青春的活力。對未來充滿期待，對夢想充滿憧憬。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）那時候...生活很簡單..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）不用擔心失蹤的家人...不用在不同的世界之間掙扎..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）只要好好讀書...準備畢業...找工作..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）我以為...人生就是這樣...按部就班...平平淡淡..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但那個神秘的列車改變了一切。他被帶到那個紫色天空的世界，然後進入了鏡像世界。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "在那個鏡像世界裡，他成為了斎藤蓮。父母變成了說日語的斎藤家。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心，苦笑）人生...果然不會按照計劃走..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰深吸一口氣，轉身離開。他不想再看了。那些美好的回憶，只會讓他更加痛苦。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他去了公園。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "社區附近的小公園。有幾張長椅，有個小湖，有幾棵老樹。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰坐在長椅上。公園裡有人在散步，有人在跑步，有老人在遛狗，有小孩在玩耍。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一個小女孩在湖邊餵魚。她的媽媽在旁邊看著她，臉上帶著溫柔的笑容。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）媽..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰想起了自己的媽媽。她也曾這樣看著他，溫柔而慈愛。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）媽...妳在哪裡..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "夕陽西下。天空染上橘紅色。湖面波光粼粼，映著天空的顏色。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "老樹的影子拉得很長。風吹過，樹葉沙沙作響。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）再見了...上海..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）不知道...下次什麼時候能回來..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）不知道...下次回來的時候...我還是不是李杰..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）還能不能...像現在這樣...坐在這裡...看著夕陽..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰坐了很久。直到天色完全暗下來，他才起身離開。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "傍晚，李杰回到酒店。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他打開行李箱，開始整理行李。衣服、盥洗用品、充電器、筆記本電腦。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把兩個盒子小心地放進背包。藍色的和紅色的，依然打不開。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（看著盒子，喃喃自語）這兩個盒子...到底藏著什麼秘密..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（嘆氣）等回到日本...再想辦法..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰整理好行李，坐在床上。他看著窗外的上海夜景。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "高樓大廈的燈光，車水馬龍的街道。這個城市，依然繁華。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）這兩週...什麼都沒找到..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）但...至少我回來了..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）至少...我又聞到了上海的味道...又吃到了上海的食物...又聽到了上海話..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）即使...我不能以李杰的身分..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "第十五天早上，李杰退房。" },
    { characterId: CharacterId.Clerk, character: "櫃檯人員", dialogue: "（微笑）謝謝您的入住，祝您旅途愉快。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（點頭）謝謝。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰拖著行李箱，走出酒店。他叫了一輛計程車。" },
    { characterId: CharacterId.Driver, character: "司機", dialogue: "（用上海話）去哪裡啊？" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（用標準中文）浦東機場。" },
    { characterId: CharacterId.Driver, character: "司機", dialogue: "（點頭）好咧。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "計程車在高速公路上飛馳。窗外的風景快速掠過。高樓大廈，逐漸遠去。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "大約一個小時後，計程車到達浦東國際機場。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "機場裡人潮洶湧。出發的、到達的、送行的、接機的。各種語言在空氣中交織。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰拖著行李箱，走向日本航空的櫃檯。他出示護照和機票。" },
    { characterId: CharacterId.Clerk, character: "櫃檯人員", dialogue: "（看著護照）斎藤蓮先生，您好。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（點頭）你好。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "辦理登機手續，托運行李，通過安檢。李杰來到登機門。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "候機室裡坐滿了人。大多是日本人，也有一些中國人。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰找了個座位坐下。他看著窗外的飛機。巨大的機身，等待著起飛。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "九月中旬了。再過兩週多，新學期就要開學了。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）這兩週...雖然沒找到大輔的線索..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）但十月開學的時候...我要把這些告訴颯真他們...一起想辦法..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）還有爸媽...他們又去了哪裡..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "登機廣播響起。" },
    { characterId: CharacterId.Announcement, character: "廣播", dialogue: "（中文和日文）飛往東京成田機場的JL886次航班現在開始登機..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰拿著登機證，走向登機口。他排在隊伍中，慢慢前進。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "登機口的工作人員檢查登機證，微笑著說：「祝您旅途愉快。」" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰登上飛機。狹窄的走道，一排排座位。他找到自己的位子，坐下。靠窗的位置。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰把背包放在腳邊。藍色和紅色的盒子，就在裡面。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "飛機開始滑行。引擎的聲音越來越大。李杰看著窗外。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "跑道，航站樓，遠處的城市。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "飛機加速，機身震動。然後，輕輕地離開地面。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "飛機爬升。上海的城市在窗外越來越小。高樓大廈變成小點，街道變成細線。" },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（看著窗外，內心）我會再回來的..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）等我弄清楚這一切..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）等我找到大輔...找到爸媽..." },
    { characterId: CharacterId.LiJie, character: "李杰", dialogue: "（內心）我一定會再回來的..." },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "飛機飛進雲層。窗外變成一片白茫茫。上海消失在視線中。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "李杰閉上眼睛，深吸一口氣。兩週的調查，雖然沒有找到大輔的下落，但至少確認了他確實在訊聯科技工作過，三個月前離職說要回日本。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "回到日本後，他要把這些告訴颯真他們，一起想辦法。" },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "飛機平穩地飛行著。兩個半小時後，就會到達東京。李杰試著休息，但腦海裡依然充滿著疑問。一切的答案，似乎都隱藏在迷霧之中。" },
];
